// src/lib/mcp/tools/generate-mock-photos.ts
import { defineTool as defineTool4 } from "npm:@lovable.dev/mcp-js@0.23.0";
import { z as z3 } from "npm:zod@^4.4.3";
function makeMockPhotos(count, seed = 0) {
  const now = Date.now();
  const day = 1e3 * 60 * 60 * 24;
  return Array.from({ length: count }, (_, i) => {
    const id = `mock-${seed}-${i}`;
    const width = 400 + i * 37 % 400;
    const height = 300 + i * 53 % 500;
    const date = new Date(now - i * day * 0.7).toISOString();
    return {
      id,
      name: `mock_${i + 1}.jpg`,
      width,
      height,
      date,
      thumbSrc: `https://picsum.photos/seed/${id}/${width}/${height}`
    };
  });
}
var generate_mock_photos_default = defineTool4({
  name: "generate_mock_photos",
  title: "Generate mock photos",
  description: "Return a deterministic list of placeholder photo entries (id, name, width, height, date, thumbSrc) matching the demo grid. Useful for testing gallery layouts.",
  inputSchema: {
    count: z3.number().int().min(1).max(200).default(24).describe("How many mock photos to return (1\u2013200)."),
    seed: z3.number().int().min(0).max(9999).default(0).describe("Seed to vary the generated set.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ count, seed }) => {
    const photos = makeMockPhotos(count, seed);
    return {
      content: [{ type: "text", text: JSON.stringify(photos, null, 2) }],
      structuredContent: { photos }
    };
  }
});

